  1→/**
  2→ * Three-layer collision detection for agent learnings.
  3→ *
  4→ * Checks new learning text against:
  5→ *   1. Existing active learnings (duplicate > 0.90, LLM classify 0.75-0.90)
  6→ *   2. Active policies (LLM classify > 0.80, contradiction = hard block)
  7→ *   3. Confirmed decisions (LLM classify > 0.80, contradiction = informational)
  8→ *
  9→ * Uses two-step KNN pattern to avoid SurrealDB HNSW + WHERE index conflict.
 10→ * LLM classification defaults to "contradicts" on failure (fail-safe).
 11→ */
 12→import { generateObject } from "ai";
 13→import { RecordId, type Surreal } from "surrealdb";
 14→import { z } from "zod";
 15→import { logInfo, logWarn } from "../http/observability";
 16→
 17→// ---------------------------------------------------------------------------
 18→// Types
 19→// ---------------------------------------------------------------------------
 20→
 21→export type CollisionClassification =
 22→  | "contradicts"
 23→  | "duplicates"
 24→  | "reinforces"
 25→  | "unrelated";
 26→
 27→export type CollisionTargetKind = "learning" | "policy" | "decision";
 28→
 29→export type CollisionResult = {
 30→  collisionType: CollisionClassification;
 31→  targetKind: CollisionTargetKind;
 32→  targetId: string;
 33→  targetText: string;
 34→  similarity: number;
 35→  blocking: boolean;
 36→  reasoning?: string;
 37→};
 38→
 39→export type CollisionCheckResult = {
 40→  collisions: CollisionResult[];
 41→  hasBlockingCollision: boolean;
 42→  deferred?: boolean;
 43→};
 44→
 45→// ---------------------------------------------------------------------------
 46→// Thresholds
 47→// ---------------------------------------------------------------------------
 48→
 49→const LEARNING_THRESHOLD = 0.75;
 50→const LEARNING_DUPLICATE_THRESHOLD = 0.90;
 51→// Cross-entity thresholds are lower because embeddings of different entity types
 52→// (learning text vs policy description vs decision summary) have lower cosine
 53→// similarity even when topically related. The LLM classifier handles accuracy.
 54→const POLICY_THRESHOLD = 0.40;
 55→const DECISION_THRESHOLD = 0.55;
 56→
 57→// ---------------------------------------------------------------------------
 58→// LLM classification schema
 59→// ---------------------------------------------------------------------------
 60→
 61→const classificationSchema = z.object({
 62→  classification: z.enum(["contradicts", "reinforces", "unrelated"]).describe(
 63→    "How learning A relates to target B: contradicts (opposite/incompatible), reinforces (compatible/complementary), unrelated (different domains)",
 64→  ),
 65→  reasoning: z.string().describe("Brief explanation of the classification"),
 66→});
 67→
 68→// ---------------------------------------------------------------------------
 69→// Main entry point
 70→// ---------------------------------------------------------------------------
 71→
 72→export async function checkCollisions(input: {
 73→  surreal: Surreal;
 74→  model: unknown;
 75→  workspaceRecord: RecordId<"workspace", string>;
 76→  learningText: string;
 77→  learningEmbedding?: number[];
 78→  source: "human" | "agent";
 79→}): Promise<CollisionCheckResult> {
 80→  const { surreal, model, workspaceRecord, learningText, learningEmbedding, source } = input;
 81→
 82→  // Fail-open/closed when embedding unavailable
 83→  if (!learningEmbedding) {
 84→    if (source === "human") {
 85→      return { collisions: [], hasBlockingCollision: false };
 86→    }
 87→    // Agent-suggested: defer collision check
 88→    return { collisions: [], hasBlockingCollision: false, deferred: true };
 89→  }
 90→
 91→  const collisions: CollisionResult[] = [];
 92→
 93→  // Layer 1: Learning-vs-learning
 94→  const learningCandidates = await findSimilarRecords(surreal, workspaceRecord, learningEmbedding, LEARNING_SPEC);
 95→  for (const candidate of learningCandidates) {
 96→    if (candidate.similarity > LEARNING_DUPLICATE_THRESHOLD) {
 97→      collisions.push({
 98→        collisionType: "duplicates",
 99→        targetKind: "learning",
100→        targetId: candidate.id,
101→        targetText: candidate.text,
102→        similarity: candidate.similarity,
103→        blocking: false,
104→      });
105→    } else if (candidate.similarity > LEARNING_THRESHOLD) {
106→      const classification = await classifyWithLlm(model, learningText, candidate.text);
107→      if (classification.classification !== "unrelated") {
108→        collisions.push({
109→          collisionType: classification.classification,
110→          targetKind: "learning",
111→          targetId: candidate.id,
112→          targetText: candidate.text,
113→          similarity: candidate.similarity,
114→          blocking: false,
115→          reasoning: classification.reasoning,
116→        });
117→      }
118→    }
119→  }
120→
121→  // Layer 2: Learning-vs-policy (contradiction = hard block)
122→  const policyCandidates = await findSimilarRecords(surreal, workspaceRecord, learningEmbedding, POLICY_SPEC);
123→  for (const candidate of policyCandidates) {
124→    const classification = await classifyWithLlm(model, learningText, candidate.text);
125→    const isContradiction = classification.classification === "contradicts";
126→    if (classification.classification !== "unrelated") {
127→      collisions.push({
128→        collisionType: classification.classification,
129→        targetKind: "policy",
130→        targetId: candidate.id,
131→        targetText: candidate.text,
132→        similarity: candidate.similarity,
133→        blocking: isContradiction,
134→        reasoning: classification.reasoning,
135→      });
136→    }
137→  }
138→
139→  // Layer 3: Learning-vs-decision (always informational)
140→  const decisionCandidates = await findSimilarRecords(surreal, workspaceRecord, learningEmbedding, DECISION_SPEC);
141→  for (const candidate of decisionCandidates) {
142→    const classification = await classifyWithLlm(model, learningText, candidate.text);
143→    if (classification.classification !== "unrelated") {
144→      collisions.push({
145→        collisionType: classification.classification,
146→        targetKind: "decision",
147→        targetId: candidate.id,
148→        targetText: candidate.text,
149→        similarity: candidate.similarity,
150→        blocking: false,
151→        reasoning: classification.reasoning,
152→      });
153→    }
154→  }
155→
156→  const hasBlockingCollision = collisions.some((c) => c.blocking);
157→
158→  logInfo("learning.collision.checked", "Collision check completed", {
159→    totalCollisions: collisions.length,
160→    hasBlockingCollision,
161→    learningCollisions: collisions.filter((c) => c.targetKind === "learning").length,
162→    policyCollisions: collisions.filter((c) => c.targetKind === "policy").length,
163→    decisionCollisions: collisions.filter((c) => c.targetKind === "decision").length,
164→  });
165→
166→  return { collisions, hasBlockingCollision };
167→}
168→
169→// ---------------------------------------------------------------------------
170→// LLM intent classification
171→// ---------------------------------------------------------------------------
172→
173→async function classifyWithLlm(
174→  model: unknown,
175→  learningText: string,
176→  targetText: string,
177→): Promise<{ classification: "contradicts" | "reinforces" | "unrelated"; reasoning: string }> {
178→  try {
179→    const result = await generateObject({
180→      model: model as any,
181→      schema: classificationSchema,
182→      temperature: 0.1,
183→      prompt: [
184→        `Given learning A: "${learningText}"`,
185→        `And target B: "${targetText}"`,
186→        "",
187→        "Classify the relationship between A and B:",
188→        "- contradicts: A and B give opposite or incompatible instructions/constraints",
189→        "- reinforces: A and B are compatible, complementary, or point in the same direction",
190→        "- unrelated: A and B are about different topics or domains with no meaningful overlap",
191→      ].join("\n"),
192→    });
193→    return result.object;
194→  } catch (error) {
195→    // Fail-safe: default to "contradicts" when LLM unavailable
196→    logWarn("learning.collision.llm_failed", "LLM classification failed, defaulting to contradicts", {
197→      error: error instanceof Error ? error.message : String(error),
198→    });
199→    return {
200→      classification: "contradicts",
201→      reasoning: "LLM classification unavailable; defaulting to contradicts for safety",
202→    };
203→  }
204→}
205→
206→// ---------------------------------------------------------------------------
207→// KNN queries (two-step pattern for SurrealDB HNSW + WHERE bug)
208→// ---------------------------------------------------------------------------
209→
210→type SimilarityCandidate = {
211→  id: string;
212→  text: string;
213→  similarity: number;
214→};
215→
216→type KnnSearchSpec = {
217→  table: string;
218→  candidateFields: string;
219→  filterFields: string;
220→  textExtractor: (row: Record<string, unknown>) => string;
221→  filterClause: string;
222→  threshold: number;
223→};
224→
225→const LEARNING_SPEC: KnnSearchSpec = {
226→  table: "learning",
227→  candidateFields: "id, text, workspace, status, vector::similarity::cosine(embedding, $embedding) AS similarity",
228→  filterFields: "id, text, similarity",
229→  textExtractor: (row) => row.text as string,
230→  filterClause: 'workspace = $ws AND status = "active"',
231→  threshold: LEARNING_THRESHOLD,
232→};
233→
234→const POLICY_SPEC: KnnSearchSpec = {
235→  table: "policy",
236→  candidateFields: "id, title, description, workspace, status, vector::similarity::cosine(embedding, $embedding) AS similarity",
237→  filterFields: "id, title, description, similarity",
238→  textExtractor: (row) => (row.description as string | undefined) ?? (row.title as string),
239→  filterClause: 'workspace = $ws AND status = "active"',
240→  threshold: POLICY_THRESHOLD,
241→};
242→
243→const DECISION_SPEC: KnnSearchSpec = {
244→  table: "decision",
245→  candidateFields: "id, summary, workspace, vector::similarity::cosine(embedding, $embedding) AS similarity",
246→  filterFields: "id, summary, similarity",
247→  textExtractor: (row) => row.summary as string,
248→  filterClause: "workspace = $ws",
249→  threshold: DECISION_THRESHOLD,
250→};
251→
252→async function findSimilarRecords(
253→  surreal: Surreal,
254→  workspaceRecord: RecordId<"workspace", string>,
255→  embedding: number[],
256→  spec: KnnSearchSpec,
257→): Promise<SimilarityCandidate[]> {
258→  const sql = `
259→    LET $candidates = SELECT ${spec.candidateFields}
260→      FROM ${spec.table} WHERE embedding <|20, COSINE|> $embedding;
261→    SELECT ${spec.filterFields} FROM $candidates
262→      WHERE ${spec.filterClause} AND similarity > ${spec.threshold}
263→      ORDER BY similarity DESC LIMIT 10;
264→  `;
265→  const results = await surreal.query<[null, Array<Record<string, unknown> & { id: RecordId; similarity: number }>]>(sql, {
266→    embedding,
267→    ws: workspaceRecord,
268→  });
269→  const rows = results[1] ?? [];
270→  return rows.map((row) => ({
271→    id: row.id.id as string,
272→    text: spec.textExtractor(row),
273→    similarity: row.similarity,
274→  }));
275→}
