 1→/**
 2→ * Pure formatter for agent learnings.
 3→ *
 4→ * No IO imports -- this module is entirely pure.
 5→ * Groups learnings by type and renders as markdown for prompt injection.
 6→ */
 7→import type { LoadedLearning } from "./loader";
 8→
 9→// ---------------------------------------------------------------------------
10→// Token estimation
11→// ---------------------------------------------------------------------------
12→
13→/**
14→ * Estimates token count from text using word-count heuristic.
15→ * Approximation: ~0.75 words per token (English text average).
16→ */
17→export function estimateTokens(text: string): number {
18→  const trimmed = text.trim();
19→  if (trimmed.length === 0) return 0;
20→  const wordCount = trimmed.split(/\s+/).length;
21→  return Math.ceil(wordCount / 0.75);
22→}
23→
24→// ---------------------------------------------------------------------------
25→// Formatter
26→// ---------------------------------------------------------------------------
27→
28→const SECTION_ORDER: ReadonlyArray<{ type: LoadedLearning["learningType"]; heading: string }> = [
29→  { type: "constraint", heading: "Constraints" },
30→  { type: "instruction", heading: "Instructions" },
31→  { type: "precedent", heading: "Precedents" },
32→];
33→
34→function formatLearningLine(learning: LoadedLearning): string {
35→  if (learning.learningType === "precedent" && learning.similarity !== undefined) {
36→    return `- ${learning.text} (similarity: ${learning.similarity.toFixed(2)})`;
37→  }
38→  return `- ${learning.text}`;
39→}
40→
41→/**
42→ * Renders learnings as a grouped markdown section.
43→ * Only includes sections that have at least one learning.
44→ * Returns empty string when no learnings provided.
45→ */
46→export function formatLearningsSection(learnings: ReadonlyArray<LoadedLearning>): string {
47→  if (learnings.length === 0) return "";
48→
49→  const sections = SECTION_ORDER
50→    .map(({ type, heading }) => {
51→      const items = learnings.filter((l) => l.learningType === type);
52→      if (items.length === 0) return undefined;
53→      const lines = items.map(formatLearningLine).join("\n");
54→      return `### ${heading}\n${lines}`;
55→    })
56→    .filter((section): section is string => section !== undefined);
57→
58→  if (sections.length === 0) return "";
59→
60→  return `## Workspace Learnings\n\n${sections.join("\n\n")}`;
61→}
