 39→export function createLearningRouteHandlers(deps: ServerDependencies) {
 40→  return {
 41→    handleCreate: (workspaceId: string, request: Request) =>
 42→      handleCreateLearning(deps, workspaceId, request),
 43→    handleList: (workspaceId: string, request: Request) =>
 44→      handleListLearnings(deps, workspaceId, request),
 45→    handleAction: (workspaceId: string, learningId: string, request: Request) =>
 46→      handleLearningAction(deps, workspaceId, learningId, request),
 47→  };
