 50→// ---------------------------------------------------------------------------
 51→// POST /api/workspaces/:workspaceId/learnings
 52→// ---------------------------------------------------------------------------
 53→
 54→type CreateBody = {
 55→  text?: string;
 56→  learning_type?: string;
 57→  priority?: string;
 58→  target_agents?: string[];
 59→};
 60→
 61→async function handleCreateLearning(
 62→  deps: ServerDependencies,
 63→  workspaceId: string,
 64→  request: Request,
 65→): Promise<Response> {
 66→  let body: CreateBody;
 67→  try {
 68→    body = (await request.json()) as CreateBody;
 69→  } catch {
 70→    return jsonError("invalid JSON body", 400);
 71→  }
 72→
 73→  // Validate required fields
 74→  if (!body.text || typeof body.text !== "string" || body.text.trim().length === 0) {
 75→    return jsonError("text is required", 400);
 76→  }
 77→  if (!body.learning_type || !LEARNING_TYPES.includes(body.learning_type as LearningType)) {
 78→    return jsonError(
 79→      `learning_type must be one of: ${LEARNING_TYPES.join(", ")}`,
 80→      400,
 81→    );
 82→  }
 83→
 84→  let workspaceRecord: RecordId<"workspace", string>;
 85→  try {
 86→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 87→  } catch (error) {
 88→    if (error instanceof HttpError) {
 89→      return jsonError(error.message, error.status);
 90→    }
 91→    logError("learning.create.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 92→    return jsonError("failed to resolve workspace", 500);
 93→  }
 94→
 95→  try {
 96→    const now = new Date();
 97→
 98→    // Attempt embedding generation (non-blocking on failure)
 99→    let embedding: number[] | undefined;
100→    try {
101→      embedding = await createEmbeddingVector(
102→        deps.embeddingModel,
103→        body.text,
104→        deps.config.embeddingDimension,
105→      );
106→    } catch (error) {
107→      logWarn("learning.create.embedding_failed", "Embedding generation failed, persisting without", {
108→        workspaceId,
109→        error: error instanceof Error ? error.message : String(error),
110→      });
111→    }
112→
113→    // Run collision detection before creating the learning
114→    const collisionResult = await checkCollisions({
115→      surreal: deps.surreal,
116→      model: deps.extractionModel,
117→      workspaceRecord,
118→      learningText: body.text.trim(),
119→      learningEmbedding: embedding,
120→      source: "human",
121→    });
122→
123→    // Determine status: blocked learnings stay pending, otherwise human-created = active
124→    const shouldBlock = collisionResult.hasBlockingCollision;
125→    const learningRecord = await createLearning({
126→      surreal: deps.surreal,
127→      workspaceRecord,
128→      learning: {
129→        text: body.text.trim(),
130→        learningType: body.learning_type as LearningType,
131→        priority: (body.priority as "low" | "medium" | "high") ?? "medium",
132→        targetAgents: body.target_agents ?? [],
133→        source: "human",
134→        ...(shouldBlock ? { forceStatus: "pending_approval" as const } : {}),
135→      },
136→      now,
137→      embedding,
138→    });
139→
140→    const learningId = learningRecord.id as string;
141→
142→    logInfo("learning.created", "Learning created via HTTP", {
143→      workspaceId,
144→      learningId,
145→      learningType: body.learning_type,
146→      hasEmbedding: embedding !== undefined,
147→      collisions: collisionResult.collisions.length,
148→      blocked: shouldBlock,
149→    });
150→
151→    const responseCollisions: CollisionResult[] = collisionResult.collisions;
152→
153→    return jsonResponse({
154→      learningId,
155→      learning: { id: learningId },
156→      collisions: responseCollisions,
157→    }, 201);
158→  } catch (error) {
159→    logError("learning.create.failed", "Failed to create learning", error, { workspaceId });
160→    return jsonError("failed to create learning", 500);
161→  }
162→}
