310→    await updateLearningStatus({
311→      surreal: deps.surreal,
312→      workspaceRecord,
313→      learningRecord,
314→      newStatus,
315→      now,
316→      reason: body.reason,
317→    });
318→
319→    logInfo("learning.action.completed", "Learning action completed", {
320→      workspaceId,
321→      learningId,
322→      action,
323→      previousStatus: existing.status,
324→      newStatus,
325→    });
326→
327→    return jsonResponse({ status: newStatus }, 200);
328→  } catch (error) {
329→    logError("learning.action.failed", "Failed to perform learning action", error, {
330→      workspaceId,
331→      learningId,
